SELECT project_name
FROM projects
ORDER BY project_name;

SELECT COUNT(*) AS total_assigned_tickets
FROM ticket_assignments
WHERE user_id = 1;

SELECT AVG(actual_time) AS average_actual_time
FROM tickets
WHERE priority = 'high' AND status = 'closed';

SELECT COUNT(*) AS in_progress_ticket_count
FROM tickets
WHERE status = 'in progress';
